(function () {
  var fallbacks = {
    "room-1.jpg": "data:image/jpeg;base64,",
    "room-2.jpg": "data:image/jpeg;base64,",
    "room-3.jpg": "data:image/jpeg;base64,",
    "room-4.jpg": "data:image/jpeg;base64,",
    "room-5.jpg": "data:image/jpeg;base64,"
  };
  function fallbackFor(src) {
    var match = String(src || "").match(/room-\d+\.jpg/i);
    return match ? fallbacks[match[0]] : null;
  }
  function applyFallback(img) {
    if (!img || img.dataset.pulseloreFallbackApplied === "yes") return;
    var fallback = fallbackFor(img.currentSrc || img.src);
    if (!fallback) return;
    img.dataset.pulseloreFallbackApplied = "yes";
    img.src = fallback;
  }
  document.addEventListener("error", function (event) {
    var target = event.target;
    if (target && target.tagName === "IMG" && String(target.src || "").indexOf("/hotel-demo/hotel-rooms/") !== -1) {
      applyFallback(target);
    }
  }, true);
  window.addEventListener("load", function () {
    setTimeout(function () {
      document.querySelectorAll("img[src*=\"/hotel-demo/hotel-rooms/\"]").forEach(function (img) {
        if (!img.complete || img.naturalWidth === 0) applyFallback(img);
      });
    }, 1200);
  });
}());
